	('c3454f21-3d9a-44cf-af8c-d534a4aafda9', '3abdbab2-010a-552f-b190-3f6a42ca3ea0', 'about', 'cards', 'About the Program', NULL, '{"items": [{"id": "a5a0f308-d183-409b-93f8-2ce2036568ae", "title": "MBA Students", "description": "5-Day Advanced Excel Workshop (SeptΓÇôOct 2019), Focused on business analytics and reporting through practical spreadsheet applications."}, {"id": "12c6f402-acbb-41a9-ba56-09d74f786975", "title": "Non-Teaching Staff", "description": "MS Office & Email Etiquette (Feb 2019) ΓÇô 3-day session on digital tools and workplace communication. Advanced Excel, Time Management & Personal Branding via Social Media (July 2019) ΓÇô 3-day program for productivity and professional presence."}, {"id": "d29d9417-852d-403c-ba34-5e52e3320f76", "title": "Civil Engineering Students", "description": "Day 1 ΓÇô Surveying & geospatial analysis using Total Station & GIS. Day 2 ΓÇô Construction Project Management tools (PERT, CPM, EVM). Day 3 ΓÇô BIM, Risk Management, and digital modeling. 60 students participated."}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:51.805488+00'),
	('f59f2df0-1920-476f-88a8-19ba114ae696', '5f257874-6d18-535f-ac5f-54f790db0f03', 'introduction', 'text', 'Global International School ΓÇô Empowering Teachers', NULL, '{"text": "Teachers shape the learning environment, but they can only transform classrooms when they are equipped and inspired. However, most lacked structured exposure to NEP-aligned pedagogy, meaningful technology integration, and effective strategies to manage young, modern learners. The shift from traditional instruction to learner-centric approaches demanded more than content knowledge. It required mindset shifts, new tools, and practical strategies. Yet, most training programs remained too theoretical or generic to create lasting change. Rareminds was invited to bridge this critical gap with focused, hands-on capacity-building for today''s classrooms.", "images": [{"id": "9713389e-f7b2-4950-be2f-995c0b5c9814", "url": "https://media.rareminds.in/1779541559190-a2a8a957-d183-4871-a57c-c0c8ef118975-3.jpg"}, {"id": "9f801fa5-29c1-4fe4-b194-0d814b321f77", "url": "https://media.rareminds.in/1779541565188-1c4044bc-527c-4fc6-97c6-e2dd791c5485-2-copy.jpg"}, {"id": "39b08fa0-64f0-451a-b685-09dc09c200e0", "url": "https://media.rareminds.in/1779541570840-5db2ff95-5295-4121-9fb5-3e4ecf66d91c-1-copy.jpg"}]}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
