name": "University of Madras", "students": 1212}]}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('05579dc6-92fa-4717-99b0-2045c8af93dd', 'e308f549-67ec-5238-9816-7b5f19fdb522', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "869d06d9-7081-4cc7-a867-11e749a640c5", "label": "Students trained in Chemical Safety in Battery Management", "value": "2,755 Students trained"}, {"id": "e8f67fed-b135-4fa3-bea0-74fd9ae8e843", "label": "Students trained in Food Analysis, Processing and Preservation Techniques", "value": "5,219 Students trained"}, {"id": "2fc31445-dd64-4a45-b156-e6b5aaaf7bf8", "label": "Students trained in Organic Food Production Techniques", "value": "991 Students trained"}, {"id": "351faf1a-e08d-40c2-8f55-776e742a5790", "label": "Students trained in Sustainability & Green Chemistry in EV Sector", "value": "7,483 Students trained"}, {"id": "b96dc1b9-e73f-4e96-ae5f-f6df4d519d95", "label": "Large-scale implementation across leading universities in Tamil Nadu", "value": "Large-scale implementation"}, {"id": "f040593f-7fe0-4dfb-895b-67fa529d2f48", "label": "Strong hands-on learning outcomes through mentor-led sessions and real-world applications", "value": "Strong hands-on learning"}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:28.112202+00'),
	('883a2276-6dbe-4e6e-8200-14c351e99812', '5f257874-6d18-535f-ac5f-54f790db0f03', 'strategic_alignment', 'cards', 'Strategic Alignment with Global International School Goals', NULL, '{"items": [{"id": "46579271-f4b2-4c7f-a948-96010de11b7b", "title": "Teacher Capacity Building", "description": "Teacher Capacity Building and NEP Integration"}, {"id": "795ea89c-ddce-4da7-8615-926092a81958", "title": "Rapid Upskilling", "description": "Rapid Upskilling with Practical Teaching Tools"}, {"id": "547eb863-a86c-49ad-b635-40a8a44c0ed3", "title": "Classroom Innovation", "description": "Personalized Classroom Innovation Initiatives"}, {"id": "53a68537-756b-4a34-aed8-9a57f37c8c2f", "title": "Student Engagement", "description": "Enhanced Student Engagement and Retention"}], "description": "This initiative directly supported the school''s goals around:"}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
	('e0284dec-b168-4183-a002-9332df83742b', '53999e9f-b693-5ed6-b9b6-e39d1e9a0196', 'modules', 'cards', 'Modules Covered', NULL, '{"items": [{"id": "656ad183-7660-4eb0-b980-1f8cfe73dec1", "title": "Industry-Oriented Communication", "description": "Industry-Oriented Communication Frameworks"}, {"id": "28924547-279c-41a4-ac78-dba6aded8eb6", "title": "Business Writing", "description": "Email and Business Writing Best Practices"}, {"id": "ab5b0d98-db9e-4d78-be3a-29083d7068de", "title": "Presentation & Interview Skills", "description": "Presentation and Interview Skills"}, {"id": "722eaa6c-6e89-403a-a56b-5e0a9f1fd61b", "title": "Group Discussions", "description": "Group Discussions and Personal Branding"}, {"id": "d3dda771-b808-43ba-8303-570797946013", "title": "Corporate Etiquette", "description": "Corporate Etiquette and Workplace Readiness"}]}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:58:52.254014+00'),
	('cd3e0068-33a2-4ba0-9b8d-74059fa9fbae', '4a7047fc-271a-5f25-a739-2e781e31fb58', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds training programs at VELS University reshaped technical education for first-year students, delivering high-impact, project-based training in emerging technologies. The initiative successfully bridged classroom learning with real-world application, equipping students with future-ready skills and confidence for the evolving digital workplaces.", "images": [{"id": "ff873eea-427a-4c34-b440-7d8b77f7b3ee", "url": "https://media.rareminds.in/1779541051031-9b611cf4-50a6-4c6f-8cc8-18a6f82d9a98-3.jpg"}, {"id": "3021779d-37be-4cee-9542-774342e3e80e", "url": "https://media.rareminds.in/1779541056420-34294b93-d6b1-467a-97ba-5c17663ec8c6-2.jpg"}, {"id": "e4cb5f36-5422-4134-9973-3dac10019254", "url": "https://media.rareminds.in/1779541062268-5545c4ad-b514-4c91-a277-107b0ab00132-1.jpg"}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:32.926746+00'),
	('ed7e64d1-0781-443a-b744-cabae809d15b', '3abdbab2-010a-552f-b190-3f6a42ca3ea0', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "Rareminds'' collaboration with DSATM highlights how focused, practical training can drive institutional growth, individual confidence, and long-term career success. By delivering real-world learning across multiple touchpoints, this partnership continues to shape a more future-ready, skilled campus ecosystem.", "image": {"id": "be5d091e-0bbe-413b-bbfb-b7f04881c0c9", "alt": "", "url": "https://media.rareminds.in/1779541149771-551a25ad-77ba-41ef-b531-c0c2b06f5625-Conclusion-copy.png"}}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:51.805488+00'),
	('b4709033-05f7-4744-a81e-3189df974860', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC Goals', NULL, '{"items": [{"id": "b057df87-fdab-4b55-aeb7-1ea0e3af92c4", "title": "Skill Development & Employability", "description": "Industry-aligned content enhanced job readiness of Arts and Science graduates"}, {"id": "b395a456-c68f-41ae-81ef-0f31f22aaf48", "title": "Curriculum Innovation", "description": "Courses aligned academic learning with evolving industry demands"}, {"id": "7c17d809-18ac-4dc9-ad6d-f4927f31a7fb", "title": "Student Engagement & Retention", "description": "Project-based methodologies improved interest, satisfaction, and retention"}, {"id": "c3c8f7d8-15d5-4b27-bb27-7435daa218d2", "title": "Workforce Readiness", "description": "Created a skilled talent pipeline in critical sectors supporting Tamil Nadu''s development"}], "description": "This initiative directly advanced the mission of the Tamil Nadu Skill Development Corporation through:"}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('b63f683e-ede7-44bd-8b08-e9535c092c16', 'b92b948a-f05f-518f-80ce-d629e5463fd4', 'video', 'text', NULL, NULL, '{"text": ""}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:46.281889+00'),
	('76052d9c-d302-4be0-ac43-4d323e37968d', 'e308f549-67ec-5238-9816-7b5f19fdb522', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "The RaremindsΓÇôTNSDC collaboration under the Naan Mudhalvan initiative demonstrates strong industry-academia synergy. By combining innovation, hands-on learning, and outcome-driven delivery, Rareminds enabled thousands of students to transition into confident, future-ready professionals.", "image": {"id": "4c1a6693-ea02-4029-866f-da349274d87e", "alt": "", "url": "https://media.rareminds.in/1779539926762-236b980f-9cf7-4d24-9efb-ebc8ab0a69ed-Conclusion-copy.png"}}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:28.112202+00'),
	('eb9cab57-ef46-49bc-89af-1d3c4e375b01', '53999e9f-b693-5ed6-b9b6-e39d1e9a0196', 'conclusion', 'text', 'Crafting Communicators, Not Just Candidates', NULL, '{"text": "At Acharya Institute, Rareminds went beyond basic communication training. We helped students shape their voice, articulate their value, and enter the professional world with poise and purpose. The impact was clear: sharper skills, stronger confidence, and a generation ready to make their mark.", "image": {"id": "76435af0-616b-42d1-8dd1-cc1ed2ad3cea", "alt": "", "url": "https://media.rareminds.in/1780041824645-77153e76-78e2-4285-83bb-4fd6f0856d0e.png"}}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:58:52.254014+00'),
	('eda7d41b-b483-48d8-8219-dd78fba61d15', '53999e9f-b693-5ed6-b9b6-e39d1e9a0196', 'introduction', 'text', 'Introduction', NULL, '{"text": "In May 2022ΓÇô2023, Rareminds conducted a high-impact 5-day Business Communication course for over 700 students across the Physiotherapy, MBA, and MCA departments. The sessions were tailored to enhance industry-specific communication, presentation skills, and professional behavior. This was followed by pre-placement readiness training for 120 MBA and 233 MCA students in 2024, building confidence right before they stepped into the hiring ecosystem.", "images": [{"id": "962004e9-445f-4850-a91a-08a441bab75b", "url": "https://media.rareminds.in/1779540767148-bfc9ee65-c812-4d9a-8b66-85453d41efea-3.jpg"}, {"id": "bdf7a668-57e9-4ad1-a506-0c4dd589138f", "url": "https://media.rareminds.in/1779540775451-fd01bcfc-cff9-4f0f-a3f1-76dab790e2d0-2-copy.jpg"}, {"id": "7cf38c57-388e-4869-bc70-bf0a3e02f289", "url": "https://media.rareminds.in/1779540782920-60b03cc7-dae1-4962-9449-d68bc4d85f43-1-copy.jpg"}]}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:58:52.254014+00'),
	('d86c73dd-c38d-4002-8d31-a8d7f8f4d14c', '3abdbab2-010a-552f-b190-3f6a42ca3ea0', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "58845725-f91d-4da1-b616-e573fbb06ec3", "label": "Participants trained across engineering, management, and staff categories", "value": "100+"}, {"id": "c70cf4c8-99a7-4143-bf20-631a1fb36bd0", "label": "Practical exposure to MS Excel, Total Station, and BIM", "value": ""}, {"id": "dece6809-1a75-4831-8b06-0e587154db17", "label": "Positive feedback for delivery, content relevance, and applicability", "value": ""}, {"id": "8727d612-39fb-4a5b-b6d4-9e32c8d505ee", "label": "Strengthened cross-functional competencies like project planning, digital communication, and personal branding", "value": ""}, {"id": "6bf98313-4f41-489a-a72f-bfdadbb09ecf", "label": "Programs led by industry experts ensured real-world context and engagement", "value": ""}]}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:51.805488+00'),
	('69270b76-a706-4ecc-beee-7a3df34c2bbb', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'strategic_alignment', 'cards', 'Strategic Alignment with BLDEA Goals', NULL, '{"items": [{"id": "9c1038fe-9b72-4823-aede-68b61a9f158e", "title": "NEP 2020 Integration", "description": "NEP 2020 Integration in Teaching Practice"}, {"id": "b89d1a9a-2012-480f-b25b-4f5032374031", "title": "Professional Development", "description": "Structured Professional Development for Staff"}, {"id": "454278eb-1185-4dbe-b093-9351f7b6897d", "title": "Student Engagement", "description": "Improved Student Engagement through Active Methodologies"}, {"id": "bf3f2554-301b-4a03-85c3-2c4460924020", "title": "Peer Mentoring", "description": "Internal Leadership Capacity through Peer Mentoring Models"}, {"id": "35fa6162-6666-4f8c-a4ca-6593c8b665ac", "title": "Outcome-Based Delivery", "description": "Outcome-Based Approaches in Academic Delivery"}], "description": "This initiative directly supported BLDEA''s commitment to:"}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('d7a24c5a-402e-4444-af5e-674e1c6a683e', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "The collaboration between Rareminds and TNSDC''s Naan Mudhalvan program stands as a model for impactful publicΓÇôprivate partnerships in higher education. By turning traditional classrooms into hubs of innovation and applied learning, Rareminds empowered thousands of students to transition from passive learners to confident, industry-ready contributors across agriculture, food technology, and healthcare sectors.", "image": {"id": "c8d43cfb-ff27-4c76-adec-c12ae0604df0", "alt": "", "url": "https://media.rareminds.in/1779541277789-81815cc1-601c-4e8a-a6b3-8ce30350d332-Conclusion-copy.png"}}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('fe058c1f-292c-4cb4-a7c2-d78539831ff4', 'b92b948a-f05f-518f-80ce-d629e5463fd4', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "The successful collaboration between Rareminds and the TNSDC''s Naan Mudhalvan program demonstrated Rareminds'' proven capacity to deliver measurable impact, reimagine classroom learning, and align with both institutional and governmental priorities. By turning classrooms into active innovation spaces, Rareminds empowered thousands of students to transition from passive learners to confident contributors in technology, agriculture, and sustainability. This initiative remains a shining example of how public-private partnerships can reshape education for a future-ready India.", "image": {"id": "9c70dc37-3e12-479b-bc8e-2b1589356b4f", "alt": "", "url": "https://media.rareminds.in/1779539886197-0347a281-1e07-488c-bcbb-29ed18bf8ba5-Conclusion-copy.png"}}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:46.281889+00'),
