	('64f54aee-e8c4-45cd-8a3f-332ec72ff5b8', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "0e00c1aa-af63-4258-b33f-66221c7649af", "label": "students were trained through structured, mentor-led sessions across partner universities in Tamil Nadu.", "value": "10,798 students trained"}, {"id": "480bcb30-d1f5-4425-8fe5-7304719d4ad9", "label": "All participants successfully completed comprehensive final projects, showcasing the practical application of their learning. Evaluations were jointly conducted by college faculty and RaremindsΓÇÖ industry experts.", "value": "projects successfully completed"}, {"id": "a345342c-097b-4ffb-bedb-6af2ab796508", "label": "Where applicable, students actively participated in mandatory hackathonsΓÇöfostering innovation, critical thinking, and collaborative problem-solving.", "value": "participated in mandatory hackathons"}, {"id": "6190f424-719c-4811-a3dc-bf873ee9b997", "label": "Employability outcomes were strengthened through integrated support for placements, internships, and real-time project experiences.", "value": "strengthened Employability"}, {"id": "0ee6933b-6a3f-4c3a-ad5d-92e541dfc10d", "label": "Institutional feedback from TNSDC and participating universities was overwhelmingly positive, noting higher student engagement, curiosity, and application-based learning.", "value": "Institutional feedback"}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('e0b1d8f5-7730-4c48-8aa1-3810ba341c36', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "a28dbbf6-9d4b-484b-93f0-d0dee1dd7942", "label": "Trained 10,210 students over 7 Months on English communication and personal development skills.", "value": "10,210"}, {"id": "13818696-a2d1-43e2-965b-b1b8c2b57141", "label": "The program was offered in 7 districts of Tamil Nadu (Nammakkal, Coimbatore, Tiruppur, Nilgiris, Erode, Salem, and Karur) in 90+ hostels.", "value": "7"}, {"id": "e08b6e60-cf96-4b07-a000-d7ecf94500ed", "label": "The program was delivered by 150+ trainers.", "value": "150+"}, {"id": "7565da75-0301-423c-93da-9039985e594c", "label": "Core Competencies: Students improved their basic English, conversational skills, and reading comprehension.", "value": "Core"}, {"id": "7fa290d7-535a-4365-a6dd-b854a6a14038", "label": "Cambridge assessments are at the heart of Rareminds'' outcome-driven approach, which is about measurable improvement (at least one CEFR level up). The following are the grades as assessed by Cambridge.", "value": "Cambridge"}, {"id": "31c6a05c-a2eb-452a-aa87-3a1722bd837a", "label": "52.14% of students achieved A2, indicating strong foundational English proficiency post-training.", "value": "52.14%"}, {"id": "0e809117-0cd9-4c9d-bb0e-5d58cb891bac", "label": "6.84% of students reached B1, showing above-basic competence and readiness for workplace communication.", "value": "6.84%"}, {"id": "109f3a4d-9079-4178-b599-7a53c48e5616", "label": "6.84% of students remained at A1, suggesting emerging skills that need continued support.", "value": "6.84%"}, {"id": "345f74a3-8b12-4f26-9a74-7fa0c95e9d31", "label": "0.85% improved from A1 to A2, demonstrating upward growth.", "value": "0.85%"}, {"id": "c4482b89-c52b-4bcb-b5aa-b7c1293c09a5", "label": "0.85% progressed from A2 to B1, showing measurable advancement.", "value": "0.85%"}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
