	('3d3af88a-3798-4437-aa96-686b05f4fce4', 'e308f549-67ec-5238-9816-7b5f19fdb522', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC Goals', NULL, '{"items": [{"id": "ac82c099-bba4-41c5-8a49-b680c37ffba6", "title": "Skill Development & Employability", "description": "Delivered industry-relevant, practical skills to Arts and Science graduates"}, {"id": "558b2c5d-410d-4fd6-bfa1-938166a7e754", "title": "Curriculum Innovation", "description": "Introduced cutting-edge, policy-aligned programs in EV and food technology sectors"}, {"id": "484620ee-6caa-4b33-a355-402150358433", "title": "Student Engagement", "description": "Strengthened participation and knowledge retention through experiential learning"}, {"id": "93e4bdc7-6380-4dcf-9d72-e4227c913a49", "title": "Workforce Readiness", "description": "Built a pipeline of skilled graduates prepared for high-demand industries"}], "description": "This initiative aligned seamlessly with TNSDC and Naan Mudhalvan objectives:"}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:28.112202+00'),
	('c24f327f-ef23-4e87-b969-05783b04645c', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds partnered with Tamil Nadu Skill Development Corporation (TNSDC) to improve English and personality development among students in government welfare hostels. This was hands-on training that equipped students with critical communication skills and confidence for their future academic and professional life.", "images": [{"id": "7bc390af-92b3-48b6-adc0-819551728686", "url": "https://media.rareminds.in/1779541421369-675d0c50-50f3-450f-8a4b-4440aaf003a8-3.jpg"}, {"id": "e74e05bc-4152-4cbf-af9b-78b940d9e8da", "url": "https://media.rareminds.in/1779541427235-f76c067f-60bd-4eb6-8630-a583ea57d331-2-copy.jpg"}, {"id": "17d9239f-6b74-42c2-89d3-22e546ffde82", "url": "https://media.rareminds.in/1779541433957-ca144265-9654-4ba1-8447-825067d0eacf-1-copy.jpg"}]}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
