	('7db3e89d-3846-4106-a2bf-013283520500', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'video', 'text', NULL, NULL, '{"text": ""}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
	('eca8af1e-39d6-4bce-a1e9-65d789b22b54', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'conclusion', 'text', 'Building Lasting Confidence', NULL, '{"text": "Rareminds delivers measurable impact in English communication and personality development across diverse learner groups. By aligning with the government''s student empowerment goals, Rareminds focuses on practical, confidence-building interventions grounded in the CEFR framework, ensuring structured and outcome-driven progress. While rote learning has its place in foundational skill-building, Rareminds integrates it with real-world communication strategies to foster both accuracy and fluency. Students gain the ability to apply language meaningfully ΓÇö in interviews, group settings, and digital communication. The program is adaptable, culturally relevant, and designed to support lifelong language confidence across regions and learner levels.", "image": {"id": "eb120499-37b5-4bae-90bf-9200363a23a0", "alt": "", "url": "https://media.rareminds.in/1779540136037-6f9e8ee1-82bb-430e-ba99-9a5bf26908dd-Conclusion-copy.png"}}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
