	('5c05fc1a-bb11-4373-a5f8-2558255840fb', '4a7047fc-271a-5f25-a739-2e781e31fb58', 'about', 'cards', 'About the Program', NULL, '{"items": [{"id": "9ec446a8-66f5-4a02-ad6c-7996ec282616", "title": "Industrial Metaverse", "description": "Two 45-hour experiential training programs ΓÇö Industrial Metaverse ΓÇö were delivered to undergraduate students as part of this collaboration. These programs combined cutting-edge tools like VR and AI with hands-on projects, enabling students to simulate real-world industrial environments from day one."}, {"id": "9f4fb848-12a0-4eef-9786-2e6069236bf1", "title": "Web Full Stack Development", "description": "Two 45-hour experiential training programs ΓÇö Web Full Stack Development ΓÇö were delivered to undergraduate students as part of this collaboration. These programs combined the MERN stack with hands-on projects, enabling students to code, build, and deploy real-world applications from day one."}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:32.926746+00'),
