	('e83580d6-4df5-45b7-8351-221851467808', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'about', 'cards', 'Program Delivery', NULL, '{"items": [{"id": "ceb8f269-bc5f-4b30-85ed-b4ddcc9ad01e", "title": "Program Structure", "description": "Total Training Hours: 10 hours. Schedule: 2 hours/day across 5 days. Participants Trained: 200 candidates in two batches of 100."}, {"id": "faa1de76-22b1-49e4-963f-1aec1bf9b353", "title": "Participant Profile", "description": "ITI graduates, diploma holders, graduates, postgraduates, and young professionals preparing for overseas placement opportunities."}, {"id": "f56e6ef6-07fc-4a3e-b862-68bf76e28cfa", "title": "Expert Training", "description": "Program delivered by Dr. Subhashini, CEO of Rareminds, bringing extensive industry experience and leadership in skill development."}]}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('89f5cac8-0009-451f-ada9-30397440f9e5', '4a7047fc-271a-5f25-a739-2e781e31fb58', 'strategic_alignment', 'cards', 'Strategic Alignment with VELS University Goals', NULL, '{"items": [{"id": "d03c2dae-e433-439a-8394-e2565022a6f0", "title": "NAAC & NIRF", "description": "Enhancement through experiential learning and tech integration"}, {"id": "69698ae6-bf1a-4ede-a15c-4ca75caa8cb7", "title": "Employability", "description": "Improved employability outcomes via skill-based, industry-aligned content"}, {"id": "3e89185b-3636-4de7-b453-569b1b3e9507", "title": "Curriculum Innovation", "description": "Aligned with NEP 2020 and industry expectations"}, {"id": "150146dc-2d95-4704-86a1-c7eb825435ff", "title": "Student Engagement", "description": "Higher engagement contributes to improved retention and satisfaction"}]}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:32.926746+00'),
	('1b20456b-80e3-43a3-9193-1e177746565f', 'b92b948a-f05f-518f-80ce-d629e5463fd4', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship program to significantly enhance the technical education landscape for Arts and Science students across Tamil Nadu. This initiative focused on delivering high-impact, project-based training in critical emerging technologies, effectively bridging traditional classroom learning with practical, real-world applications."}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:46.281889+00'),
	('a7cc4d97-4078-4150-8151-0c0362be9165', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'impact', 'stats', 'Objectives', NULL, '{"items": [{"id": "a7b75f2a-6f6f-49fc-a529-c1798e155c47", "label": "Students to be trained through hands-on, mentor-led sessions across major Tamil Nadu universities", "value": "14,495 Students trained"}, {"id": "7d30cfb5-6b2b-42ad-a5dd-9195fdbc353a", "label": "Project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts", "value": "100% Project completion"}, {"id": "505a7b3b-b677-418a-8352-d5b1f7157778", "label": "Student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving", "value": "70%+ Student participation"}, {"id": "44d8961a-692f-4494-8cfb-4786bec03152", "label": "Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion.", "value": "25% Enhanced employability"}, {"id": "be28f7b7-8558-4d86-8884-cac26ee588d3", "label": "Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students", "value": "Positive feedback"}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('4c38604c-d330-4fed-8374-41df9d435b63', 'b92b948a-f05f-518f-80ce-d629e5463fd4', 'about', 'text', 'About the Program', NULL, '{"text": "Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semester of the 2023ΓÇô2024 academic year. Mandatory courses covered: Agribusiness Management, EV Battery Management, Food Analysis, and Organic Food Production Techniques. Each program combined theoretical knowledge with practical application, supported by physical classroom interventions and supplementary LMS-based content for a blended learning experience."}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:46.281889+00'),
	('35a0cf0c-d138-4546-8fd1-8271d1c5a7ea', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC & Government Goals', NULL, '{"items": [{"id": "0e7333b7-b0ff-4164-b0b6-64d7eeff7757", "title": "Empowering Underprivileged Students", "description": "Training life and communication skills in Tribal, ADW, BC, MBC, DNC, and Minority welfare hostels"}, {"id": "0205c21a-0a42-4fe1-b05e-598129605421", "title": "Better Job Prospects", "description": "Building confidence and communication skills for better future opportunities"}, {"id": "423c77cf-f285-4eba-98d5-c1f729aa4093", "title": "Quality Assurance", "description": "Cambridge University Press independent standardized assessments for accountability"}, {"id": "29ec5c52-6af0-4c70-92ab-b96c7c1901f8", "title": "Practical English", "description": "Practical English for daily use and future opportunities, not just academic proficiency"}], "description": "The initiative supported TNSDC and the Government of Tamil Nadu''s key objectives:"}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
	('ff8ad8a7-d7b4-45b1-b07e-2b67f5c78b3b', '5f257874-6d18-535f-ac5f-54f790db0f03', 'modules', 'cards', 'Modules Covered', NULL, '{"items": [{"id": "8c99315d-653f-4b0a-8f63-fe4d807c1f8a", "title": "Contemporary Education", "description": "Contemporary Education and Classroom Skills"}, {"id": "38af7b68-b09c-4fb3-a308-ac6da32e4fe6", "title": "Digital Tools", "description": "Digital Tools for Teaching"}, {"id": "4de3856b-4feb-462a-b605-aeb237ab72cd", "title": "Feedback Culture", "description": "Creating a Feedback Culture"}, {"id": "fad6f524-0790-4bca-a67a-69b7251f3e41", "title": "Learner Profiles", "description": "Student Engagement Based on Learner Profiles"}, {"id": "57dc108d-f0d5-45c8-9748-4ea19ec7a9a1", "title": "Activity-Based Teaching", "description": "Activity-Based Teaching Modules"}, {"id": "7bce3239-2d83-4657-aaa3-33f65e0f7629", "title": "Action Planning", "description": "Personalized Reflection and Action Planning"}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
	('13979217-c4b9-4f29-97e7-599db2a5387c', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'video', 'text', NULL, NULL, '{"text": ""}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('5e265974-c0fe-4aa4-b69f-f19cd98cb6ab', '4a7047fc-271a-5f25-a739-2e781e31fb58', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "This successful collaboration with VELS University demonstrated Rareminds'' ability to deliver measurable outcomes, transform student learning, and align with institutional goals. By turning classrooms into innovation labs, we empowered students to become creators, not just consumers of technology.", "image": {"id": "9293f2da-5412-471b-bc57-dd349bdba7a1", "alt": "", "url": "https://media.rareminds.in/1780041882835-5b16da36-8139-4a25-a82c-e99dd1531913.png"}}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:32.926746+00'),
	('5ff08a5f-59a9-4eda-befb-f5c5e2762c92', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'introduction', 'text', 'Equipping Candidates for Global Careers with Confidence & Clarity', NULL, '{"text": "Overseas job interviews demand more than just qualifications ΓÇö they require candidates to present themselves with poise, adapt to cross-cultural environments, and navigate high-stakes conversations effectively. Tripura Skill Development Corporation (TSDC) identified the need to prepare aspiring overseas placement candidates with focused, practical training that would address both interview performance and communication competency. A targeted approach was implemented to ensure that participants ΓÇö ranging from ITI graduates to young professionals ΓÇö received actionable strategies, hands-on practice, and cross-cultural readiness for international job markets. Rareminds, under the leadership of CEO Dr. Subhashini, delivered a structured 10-hour training program (2 hours/day across 5 days) for 200 candidates in two batches of 100 each, covering ITI graduates, diploma holders, graduates, postgraduates, and young professionals. Dr. Subhashini personally conducted the sessions, bringing strategic insights and real-world experience directly to participants.", "images": [{"id": "c9b38383-4ad9-4a8a-b99a-2bc930deed4f", "url": "https://media.rareminds.in/1779541362272-9cb5333a-f6eb-43c0-9a7d-de5b7d91b281-3.jpg"}, {"id": "ff09d11d-0ac2-44aa-96c9-e1dde1f1fbfe", "url": "https://media.rareminds.in/1779541369108-72db9af8-7541-4788-b716-25c54d3772f9-2-copy.jpg"}, {"id": "bb7cfab8-2599-446e-ac8e-7ff90bfe442d", "url": "https://media.rareminds.in/1779541375936-06da81cf-3d9f-4f92-923f-4ab8233c971c-1-copy.jpg"}]}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('6ded7d0a-97d0-49f0-894d-d0dcc00aa059', '53999e9f-b693-5ed6-b9b6-e39d1e9a0196', 'impact', 'stats', 'Outcomes and Impact', NULL, '{"items": [{"id": "4efc5c70-fbea-46c4-a530-494cb2a924e1", "label": "Students reported increased clarity and confidence in job interviews", "value": "85%"}, {"id": "defdb56d-e41a-415d-8548-2bd8f0378d3f", "label": "Campus recruiters highlighted better articulation and professionalism", "value": ""}, {"id": "dd9955dc-9262-47e0-a08f-b0670df8034c", "label": "MBA & MCA placement coordinators reported smoother pre-placement processes", "value": ""}]}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:58:52.254014+00'),
	('54a73b24-2174-459e-a805-4b7709c0b29e', '5f257874-6d18-535f-ac5f-54f790db0f03', 'impact', 'stats', 'Outcomes and Impact', NULL, '{"items": [{"id": "48f995e9-42e5-45b6-9ad3-c7c4931c1eb5", "label": "Participation and engagement across all sessions", "value": "100%"}, {"id": "5e861d2e-e89e-42a8-9adc-49e1658efb35", "label": "Teachers developed classroom innovation plans post-training", "value": ""}, {"id": "d64d53df-f160-4de8-b48e-535c08e61b08", "label": "Improved lesson planning confidence and use of engagement tools", "value": ""}]}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
	('bb1e662d-2a4e-4316-ad5c-01f3cf7741ff', '5f257874-6d18-535f-ac5f-54f790db0f03', 'conclusion', 'text', 'Conclusion: Turning Educators into Enablers', NULL, '{"text": "At Global International School, Rareminds supported teachers to go beyond delivery. By equipping them with modern strategies, tech tools, and learner-focused frameworks, we helped lay the groundwork for classrooms that are engaging, inclusive, and impact-driven. It was more than trainingΓÇöit was a catalyst for everyday transformation.", "image": {"id": "2199da10-aed6-48fd-8218-03eb344db34d", "alt": "", "url": "https://media.rareminds.in/1779540371665-d7d8bb5e-70a7-4910-833b-8ee76150049f-Conclusion-copy.png"}}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
	('a16614e2-6a72-48e0-9321-c61bae1b7c11', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'video', 'text', NULL, NULL, '{"text": ""}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('ee4d8bb9-5e43-4fba-82a0-209942584a03', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'impact', 'stats', 'Outcomes and Impact', NULL, '{"items": [{"id": "e9c891d9-4112-470f-baad-93ed7a50c4e5", "label": "Participants reported improved confidence in handling interviews", "value": "95%"}, {"id": "91227dab-8011-47e1-a0a0-d7c183c0d2a4", "label": "Demonstrated better articulation in mock interview evaluations", "value": "92%"}, {"id": "ecbff1c3-6d66-42fd-a0b8-0e3cd7fa42a2", "label": "Showed improvement in cross-cultural awareness and etiquette", "value": "87%"}, {"id": "8298df6a-82ca-496f-8dd6-47d868c6e155", "label": "Completed mock interviews with personalized feedback", "value": "100%"}, {"id": "c16a1f3f-83b4-40ea-b093-5610b692d34c", "label": "Average improvement in self-assessment scores across key skill areas", "value": "40%"}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('17cb8d29-692d-49e0-9eae-14f8dfa19653', '53999e9f-b693-5ed6-b9b6-e39d1e9a0196', 'header', 'text', 'From Campus Conversations to Corporate Confidence', NULL, '{"text": "Great careers begin with clear communication. At Acharya Institute, Bangalore, the gap between technical skills and professional readiness was evident among students preparing for the job market. Recognizing this, Rareminds was brought in to bridge the communication gap and empower students with the skills they need to thrive in the real world."}', 7, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:58:52.254014+00'),
	('d9918c14-4216-417d-b340-0b67e7f3c659', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC Goals', NULL, '{"items": [{"id": "4dc96c7f-9ecc-446d-9d6d-12f947cd6b3d", "title": "Skill Development & Employability", "description": "Provide students with industry-relevant, practical skills"}, {"id": "0289c25c-d5ae-44c8-83fd-c682683e308b", "title": "Curriculum Innovation", "description": "Introduce cutting-edge topics aligned with national education policy"}, {"id": "d7baab8a-dc54-4214-8626-50af86cfb9e0", "title": "Student Engagement", "description": "Elevate learning interest through experiential pedagogy"}, {"id": "a78ea7e9-7c6c-4753-a9f5-e4504748d248", "title": "Workforce Readiness", "description": "Create a pipeline of skilled graduates prepared for high-demand industries"}], "description": "This initiative aligned seamlessly with TNSDC and Naan Mudhalvan objectives:"}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('5be12d0b-6e74-4540-810e-d094d22a0692', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'approaches', 'cards', 'Multiple Approaches', NULL, '{"items": [{"id": "f45cd405-af97-4b40-9edd-e96a6403094b", "title": "Presentations & Case Studies", "description": "Interactive Presentations & Case Studies"}, {"id": "5c97f5f6-1236-431a-9c9e-fee490da2216", "title": "Group Discussions", "description": "Group Discussions & Peer Activities"}, {"id": "ba5e6417-e633-4fdd-9f9d-5defe1d8c27f", "title": "Roleplays & Simulations", "description": "Roleplays & Interview Simulations"}, {"id": "03ca65e6-5de0-4d3d-9b0c-f1a1b84f294b", "title": "Individualized Coaching", "description": "Individualized Coaching & Feedback"}]}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('f5783c2c-9ce6-4ed2-9c46-afdd029ee569', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'conclusion', 'text', 'Turning Aspirants into Global Professionals', NULL, '{"text": "Through this focused intervention, Rareminds ΓÇö under the direct leadership and facilitation of CEO Dr. Subhashini ΓÇö empowered Tripura''s overseas placement aspirants with the tools, confidence, and global readiness essential for success. The program served not only as a skill-building platform but also as a mindset transformation, directly contributing to TSDC''s vision of creating globally competitive talent.", "image": {"id": "c6bf5a62-261b-4ff4-9e91-40900c05625c", "alt": "", "url": "https://media.rareminds.in/1779540091981-ff1bf243-005b-4931-a719-12d9401e8345-Conclusion-copy.png"}}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('dd7fa571-fc72-41d3-9fca-98140cccf087', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'introduction', 'text', 'Introduction', NULL, '{"text": "The Rareminds Bootcamp at PES Engineering College, Mandya, contributed to transform aspiring engineers into confident, industry-ready developers. Through an intensive, 45-hour Web Development Bootcamp, we bridged the classroom-to-career gap with a hands-on, real-world coding experience that left students skilled, motivated, and ready for the digital future.", "images": [{"id": "7d924add-c394-4230-b5de-b317acc194ee", "url": "https://media.rareminds.in/1779540982677-1c675007-35f9-4519-9470-3bd2b2b13839-3.jpg"}, {"id": "7ee2b7ca-0daa-4ed1-a486-107848478c6d", "url": "https://media.rareminds.in/1779540989578-9c1f7217-e705-4eb6-856d-14384f8e1085-2-copy.jpg"}, {"id": "736b1451-7df9-477b-a21f-869a486148ef", "url": "https://media.rareminds.in/1779540998323-4902710f-eca7-4d7c-9f43-683b41380a25-1-copy.jpg"}]}', 0, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('f90a2275-88f2-4e9c-997d-1b169abf3423', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'about', 'cards', 'About the Program', NULL, '{"items": [{"id": "52ea2227-b0aa-4781-9d67-85a8e3d0c199", "title": "Web Development Bootcamp", "description": "From July 24th to 29th, 2023, Rareminds delivered a comprehensive Web Development Bootcamp focused on Full Stack skills. The program immersed students in practical learning, from HTML, CSS, and JavaScript to React, backend integration, APIs, and deployment techniques."}, {"id": "2b7d195f-77a5-4328-bcb2-4d38b70adb44", "title": "Hands-On Learning", "description": "Designed around active problem-solving, teamwork, and real-time feedback, this initiative gave students the tools to think like developers and build like professionals."}]}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('04540246-be6d-4c6c-a548-656dbafdb123', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "00a5c75a-b179-4096-aa7c-dbb02e4d4bfc", "label": "Students trained through immersive bootcamp sessions combining technical depth and collaborative learning.", "value": "100+"}, {"id": "2071dfa0-9def-43e7-86ea-bf9e1bde8149", "label": "Built fully functional web applications from scratch", "value": "70%"}, {"id": "bcaf2536-b5cd-4f55-9ba6-cc94ac28bfe3", "label": "Actively participated in hands-on coding and real-time problem-solving", "value": "90%"}, {"id": "3cc16bcb-8962-450f-914c-8cbeb2bfce10", "label": "Expressed confidence in building, securing, and deploying full-stack web applications", "value": "100%"}, {"id": "ec181088-b7e8-499e-b548-80efee157efc", "label": "Reported improved critical thinking and collaboration skills", "value": "85%"}, {"id": "9434573f-5f84-4a51-94ec-18852c9a1886", "label": "Showed growth in communication and teamwork via pair programming", "value": "92%"}, {"id": "9f6a0faa-de9d-4382-8b33-e5ca263c0689", "label": "Can now clearly articulate technical ideas for interviews and presentations", "value": "88%"}]}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('fcb20125-953b-4a70-b034-845721627abd', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'conclusion', 'text', 'Turning Teachers into Changemakers', NULL, '{"text": "At BLDEA Schools, Rareminds didn''t just train teachersΓÇöwe helped shift the culture of classrooms. By building both confidence and capability, our approach enabled teachers to become reflective practitioners who lead learning with clarity, care, and consistency. Together, we laid the foundation for a sustainable teaching excellence model rooted in purpose, pedagogy, and practice.", "image": {"id": "6d5db6df-6bd2-4447-809a-db4472fdf98a", "alt": "", "url": "https://media.rareminds.in/1779541235542-3ce38b9f-460e-4833-93b3-2f17d99aa82f-Conclusion-copy.png"}}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('b193c438-7782-4e76-9d02-5e8b653a30e6', 'fc65048f-7586-5051-b352-6313d9dfa7a9', 'about', 'cards', 'About the Program', NULL, '{"items": [{"id": "e9380fe2-3109-4f3f-a4ec-39f2b1be7fdf", "title": "Target Audience", "description": "Full English and Personality Development program offered to 2nd and 3rd year students in Tribal, ADW, BC, MBC, DNC, and Minorities Welfare Department Hostels."}, {"id": "290c736f-3e22-444b-9943-bc5a772301f0", "title": "Curriculum Approach", "description": "The curriculum used open-source documentary movies for listening/speaking practice, English newspapers for reading/writing, and dedicated workbooks for structured assessments."}, {"id": "479f019f-5e0c-45bf-b923-9aaa7dc637b4", "title": "Assessment & Certification", "description": "Cambridge University administered pre- and post-training exams to monitor student progress and track improvement on the CEFR scale."}]}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:05:52.698687+00'),
	('d0c2a5cd-244a-4d8c-a549-f49ad8bd7a18', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'strategic_alignment', 'cards', 'Strategic Alignment with PES College Goals', NULL, '{"items": [{"id": "7df109f0-24a2-43e4-aa05-492b477d7c00", "title": "Skill-Based Learning", "description": "Skill-Based, Industry-Ready Learning"}, {"id": "4516bab6-0430-4e43-9b58-a94500116fdb", "title": "NAAC / NIRF", "description": "NAAC and NIRF Enhancement through Outcome-Focused Programs"}, {"id": "32d7a279-c8e3-403c-976c-436f45bd85a3", "title": "Innovation Culture", "description": "Innovation and Startup Culture among Students"}, {"id": "bc5a0800-aec0-48b1-b649-424f8ebb0747", "title": "Placement Readiness", "description": "Improved Placement Readiness with Practical Tech Exposure"}, {"id": "118ee548-26ba-4a1c-82ea-cb999b1cf45c", "title": "NEP 2020 Alignment", "description": "NEP 2020 Alignment through experiential, future-focused education"}], "description": "This initiative supported key institutional objectives such as:"}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('f2b2d1a9-bc3a-426e-ab0a-cd9b1094d45b', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'conclusion', 'text', 'Turning Coders into Creators', NULL, '{"text": "At PES Engineering College, Rareminds didn''t just teach programming ΓÇö we built a culture of innovation, confidence, and readiness. By empowering students to develop real solutions, communicate effectively, and collaborate as tech professionals, we helped transform the campus into a launchpad for tomorrow''s digital leaders.", "image": {"id": "8797dd6e-fe31-4ba8-9ddc-fa894f679c62", "alt": "", "url": "https://media.rareminds.in/1779542676455-1d7a909d-1474-4239-8100-3102d58964dc-Conclusion-copy.png"}}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('7e0c8991-cbfc-499b-8d4f-8c81fb5c597c', '0b807def-c7b4-569a-b4b2-23c0a1d3c92a', 'video', 'text', NULL, NULL, '{"text": ""}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:16.160454+00'),
	('41d25f8a-fb04-4876-86d7-6afccb7dd715', '3abdbab2-010a-552f-b190-3f6a42ca3ea0', 'introduction', 'text', 'The Real-World Leap: How DSATM Students Gained a Competitive Edge', NULL, '{"text": "Rareminds has been a long-standing training partner for DSATM, driving student employability through curated, career-oriented workshops. By integrating both technical and soft skill components, these programs empowered engineering and management students with practical tools to thrive in professional settings.", "images": [{"id": "5036bba1-1c14-4f96-9f4a-cc16f089f04c", "url": "https://media.rareminds.in/1779541126919-3f8725e3-51ad-47c6-b302-993afe0ce158-3.jpg"}, {"id": "f3553b7d-f1ce-44b2-8008-bf92250a75ee", "url": "https://media.rareminds.in/1779541132406-bc0e4c1a-95ee-487b-9b70-1966feb3112c-2-copy.jpg"}, {"id": "63136fb5-56aa-4712-b121-1945c5d6d5f1", "url": "https://media.rareminds.in/1779541138103-abf0b637-d2ec-43c5-b842-2e5f7c5fb3bd-1-copy.jpg"}]}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 10:59:51.805488+00'),
	('d5fb5346-ce69-414a-9852-d6fb1d6c3fbc', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologiesΓÇöbridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce."}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('415b3302-acc4-4324-8f85-2999e26b844d', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'introduction', 'text', 'Elevating Everyday Teaching into Transformational Practice', NULL, '{"text": "Building great schools begins with investing in great teachers. BLDEA Schools in Karnataka recognized the need to move beyond routine training and focus on structured, high-impact development. Teachers were navigating classrooms without consistent support in pedagogy, communication, emotional intelligence, and NEP-aligned practices. A unified approach was necessary to ensure that professional growth was intact across levels and that the student engagement remained consistent, meaningful, and aligned with evolving learning needs. Rareminds delivered a concentrated, practice-based model focused on both mindset and method. Rareminds conducted a 3-day intensive program for over 200 teachers across the BLDEA network. Sessions were led by 5 master trainers and grounded in real classroom challenges.", "images": [{"id": "bb278a04-92e7-423b-a915-f4f09a4231f8", "url": "https://media.rareminds.in/1779541198992-e5e34659-8d4c-4782-bbc1-1f8b38d6a9d4-3.jpg"}, {"id": "95bcee19-dfe2-442f-8188-65ca0de84a26", "url": "https://media.rareminds.in/1779541204964-507adf0f-60d8-4578-b64b-d104c7b003ec-2-copy.jpg"}, {"id": "708ea3ad-9594-4049-9c79-9b3019c76ee4", "url": "https://media.rareminds.in/1779541211041-0328e019-8f99-4fb8-89aa-88e5a1634d85-1.jpg"}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('57cf28fd-d0f1-4cb4-b7e9-572a97971274', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'modules', 'cards', 'Modules Covered', NULL, '{"items": [{"id": "5a7e7ed4-821e-48c2-a49b-8a5eb0f961c6", "title": "NEP 2020 Alignment", "description": "NEP 2020 Alignment and Classroom Planning"}, {"id": "4030b661-1199-4e82-ba18-cc30abdca307", "title": "Assessment Frameworks", "description": "Assessment Frameworks and Tools"}, {"id": "25665a1a-0cba-46a4-a16b-c58e48718d88", "title": "Inclusive Teaching", "description": "Inclusive Teaching Practices"}, {"id": "c993bfa7-9bfd-4ace-b7a2-d79552f414fb", "title": "Empathy in Education", "description": "Empathy in Education"}, {"id": "bb388804-5686-466f-b0cb-1e401c36518e", "title": "Student Motivation", "description": "Positive Engagement and Student Motivation"}]}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('13026d11-b2c3-4d46-80f9-53a552142860', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'approaches', 'cards', 'Multiple Approaches', NULL, '{"items": [{"id": "6bb258db-9e9f-4c47-b536-d91ad2f2ef7c", "title": "Roleplays", "description": "Roleplays and Scenario-Based Problem Solving"}, {"id": "1547a923-14a8-4b25-a1ca-e9e40c76e77b", "title": "Lesson Design Labs", "description": "Lesson Design Labs"}, {"id": "5f57155c-e8a5-4e15-a92b-7767a7ee8148", "title": "Peer Reflection", "description": "Peer Reflection Circles and Collaborative Planning"}]}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('761648cf-3b2c-4a00-a457-052785c97a0f', '8588ee3e-95e0-5e40-84c2-76ab3fb5dd09', 'impact', 'stats', 'Outcomes and Impact', NULL, '{"items": [{"id": "debff4fb-7f0b-46d9-8b6f-d1b23ffca637", "label": "Teachers submitted revised lesson plans aligned to new practices", "value": "90%"}, {"id": "2e6394c2-d280-4bdd-9853-1cb7a5dc0e8b", "label": "Higher ownership, clarity, and classroom strategy observed", "value": ""}, {"id": "ad445054-6828-4265-994a-90d62d211bc2", "label": "School leadership committed to ongoing mentoring circles and internal CPD", "value": ""}]}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:09.412213+00'),
	('bad6bad0-3d92-4ce0-8302-676ecbebcefc', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'about', 'text', 'About the Program', NULL, '{"text": "Through this collaboration, Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semesters of the 2024ΓÇô2025 academic year. These mandatory programs provided immersive, hands-on learning experiences in: Organic Food Practices, Food Analysis Processing and Preservation, Medical Coding, and Agri Business Management. Each course blended in-person instruction with LMS-based support, enabling students to work on real-time simulations, hands-on projects, and practical applications from day one."}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('851b61e8-1132-4d1a-8b2e-ba57b89bd25a', 'c989b977-3ede-557c-a9bb-12cddc1b8100', 'video', 'text', NULL, NULL, '{"text": ""}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:00:32.452878+00'),
	('218b9c90-a29a-45e8-a4b0-022b7e8c59fa', '1c744567-ed5a-5c30-8e1b-454ce8fdda79', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC Goals', NULL, '{"items": [{"id": "5f0117fa-1d8a-4cb7-9c1d-f0d0836b3b07", "title": "Skill Development & Employability", "description": "Delivered industry-relevant, practical skills to Arts and Science graduates"}, {"id": "30f78d0f-8655-46b2-ad0e-91fab0e9a6d2", "title": "Curriculum Innovation", "description": "Introduced cutting-edge EV technology topics aligned with industry demands"}, {"id": "aac5aeac-c1c2-4c5c-9c99-8284a27b3929", "title": "Student Engagement", "description": "Strengthened participation and curiosity through experiential learning"}, {"id": "8dd0db1b-437d-443e-b279-adf24b048245", "title": "Workforce Readiness", "description": "Built a pipeline of skilled graduates prepared for the EV sector"}], "description": "The RaremindsΓÇôTNSDC collaboration under the Naan Mudhalvan initiative exemplifies impactful industry-academia synergy:"}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:37.788223+00'),
	('48dea330-a5dc-46b8-9710-070c55999475', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologiesΓÇöbridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce."}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('1cc45796-0df5-4e78-813f-3ab5e0983c06', 'e308f549-67ec-5238-9816-7b5f19fdb522', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. The program delivered high-impact, project-based training in emerging technologies, effectively bridging classroom theory with real-world application. It empowered students with future-ready skills, practical exposure, and the confidence to meet evolving industry demands."}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:28.112202+00'),
	('eb5124b7-c372-43c6-ac6b-05cb9f20d547', 'e308f549-67ec-5238-9816-7b5f19fdb522', 'about', 'text', 'About the Program', NULL, '{"text": "Rareminds delivered specialized 45-hour experiential training programs to undergraduate students during the 4th Semester of the 2024ΓÇô2025 academic year. These mandatory programs offered immersive, hands-on learning in the following domains: Chemical Safety in Battery Management, Food Analysis Processing and Preservation Techniques, Organic Food Production Techniques, and Sustainability & Green Chemistry in EV Sector. The programs combined in-person instruction with LMS-based support, enabling students to engage in real-time simulations, projects, and practical applications from day one."}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:28.112202+00'),
	('f6dccd3b-9689-4796-bbea-78dfcc19cc26', '1c744567-ed5a-5c30-8e1b-454ce8fdda79', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "The RaremindsΓÇôTNSDC collaboration under the Naan Mudhalvan initiative highlights the effectiveness of large-scale, outcome-driven training. By equipping students with practical skills and industry exposure, the program strengthened workforce readiness and created a scalable model for education transformation.", "image": {"id": "be60018d-2743-4495-9298-14127284e4f9", "alt": "", "url": "https://media.rareminds.in/1779539971628-c9f14cce-8e1f-41d6-b260-ac928b0d08d9-Conclusion-copy.png"}}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:37.788223+00'),
