	('dc609113-4d04-424e-bcbc-8b4f9084e165', '1c744567-ed5a-5c30-8e1b-454ce8fdda79', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to enhance technical education for Arts and Science students across Tamil Nadu. The program focused on delivering project-based training in emerging technologies, bridging academic learning with practical industry application."}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:37.788223+00'),
	('2f90068f-4c41-48e6-9282-c28953ff5c73', '1c744567-ed5a-5c30-8e1b-454ce8fdda79', 'about', 'text', 'About the Program', NULL, '{"text": "Rareminds delivered a specialized 45-hour experiential training program during the 6th Semester of the 2024ΓÇô2025 academic year focused on EV Battery Management System. The mandatory program combined in-person sessions with LMS-enabled learning, allowing students to work on simulations, projects, and practical applications from the outset."}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:01:37.788223+00'),
	('c47a6332-beaf-468b-9f45-81d6d4f9e58c', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'about', 'text', 'About the Program', NULL, '{"text": "Through this collaboration, Rareminds delivered three specialized 45-hour experiential training programs to undergraduate students during the Odd Semester (5th) of the 2025ΓÇô2026 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Good Manufacturing Practices, Medical Coding, and Food Safety and Quality Management. The courses blended in-person classes with LMS-based support, enabling students to work on real-time simulations, projects, and practical applications from day one."}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
