-4f0f-96cd-37bf9fc28a7a", "name": "Bharathiar University", "students": 301}, {"id": "126604cd-242f-4674-baff-8420113febaa", "name": "Alagappa University", "students": 292}, {"id": "e9e662f6-d817-4e03-bcba-047812dc4477", "name": "Madurai Kamaraj University", "students": 157}, {"id": "b16f9da7-2e3e-4ce2-81f9-169eca67a5be", "name": "Mother Teresa University", "students": 118}]}]}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('2cb7fb9c-95d8-4c60-a9a3-793bfafc5e06', '3607a0ae-0020-54fd-80a9-8ee0afc97aa4', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "The RaremindsΓÇôTNSDC collaboration under the Naan Mudhalvan initiative exemplifies impactful industry-academia synergy. By integrating innovation, hands-on learning, and outcome-driven models, Rareminds helped thousands of students transition from passive learners to future-ready professionals. This program stands as a scalable model for education transformation and skill empowerment across India.", "image": {"id": "8dafcc16-2222-4a82-b24d-e67abcaa2a8d", "alt": "", "url": "https://media.rareminds.in/1779540025455-98fb63f4-d2eb-4112-8308-c166d582face-Conclusion-copy.png"}}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:20.58143+00'),
	('ca0612ae-9715-4dbb-8503-6d1c9b7abea1', '19a47376-0eb9-5496-82d2-9fa063ec02ca', 'impact', 'stats', 'Key Outcomes & Impact', NULL, '{"items": [{"id": "d2260984-a2be-4f25-a0c1-d96745c567f5", "label": "The program was implemented across 121 Government Higher Secondary Schools (GHSS).", "value": "121"}, {"id": "15e476c7-3079-4885-b867-35e5503c2a70", "label": "1,974 students were successfully trained", "value": "1,974"}, {"id": "bae30f30-4749-4545-b875-a8e61aa96b2d", "label": "Five Villupuram schools successfully implemented the Cloud Kitchen entrepreneurship program, training 76 aspiring food entrepreneurs.", "value": "76"}, {"id": "ae6002e2-20f4-45a6-b0da-e9e086db3e0e", "label": "The Agri-Food Processing & Preservation program was implemented in 116 schools, where 1,570 students gained practical skills and knowledge and started their home business", "value": "1,570"}, {"id": "7d93c8e8-6102-43aa-bacc-6178f19c49f0", "label": "Students gained hands-on experience through activities such as canning, bottling, pickling, fermentation, drying, and freezing techniques.", "value": "Γ£ô"}, {"id": "795f86b3-02d1-4d29-965d-3928bf042589", "label": "Students were introduced to food safety principles, hygiene practices, HACCP basics, and quality control measures.", "value": "Γ£ô"}, {"id": "d645c888-ac79-48a1-8640-5185b121fc2a", "label": "Students who started business registered under FSSAI", "value": "Γ£ô"}]}', 1, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:40.335241+00'),
	('b5db95de-1f13-496d-a0ec-4ff979ebefec', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'video', 'text', NULL, NULL, '{"text": ""}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('e6c54499-7b00-45d5-a165-84e461dad814', '1ce45cbc-8710-5bd3-90ec-6192ecc89492', 'modules', 'cards', 'Modules Covered', NULL, '{"items": [{"id": "360efb6d-b827-4bae-aeb9-c3c6b7746c52", "title": "Resume & Cover Letter", "description": "Effective Resume and Cover Letter Writing"}, {"id": "269d01db-c7ad-4e3b-807d-3ad6b4cf8442", "title": "Interview Best Practices", "description": "Common Interview Questions & Best Practices"}, {"id": "6d4725cf-850c-40b5-9d95-6f14a6610a74", "title": "Non-verbal Communication", "description": "Non-verbal Communication & Body Language"}, {"id": "67ecd6ae-0145-4d25-9249-0bd21c159145", "title": "Stress Management", "description": "Handling Difficult Questions & Stress Management"}, {"id": "d550b409-f5d9-4c8a-af81-d0e6853f0593", "title": "Mock Interviews", "description": "Mock Interviews with Personalized Feedback"}, {"id": "6cb471bd-c010-41a5-89d8-7d7efd0355ab", "title": "Cross-cultural Communication", "description": "Understanding Cultural Differences and Sensitivities"}, {"id": "55de773d-0cb8-4490-a9e3-be4580ba86b8", "title": "Global Business Etiquette", "description": "Global Business Etiquette and Intercultural Negotiation"}]}', 7, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:15.128288+00'),
	('f02dfae3-3f60-48ce-8080-1948347872c0', '19a47376-0eb9-5496-82d2-9fa063ec02ca', 'introduction', 'text', 'Introduction', NULL, '{"text": "Rareminds, in a significant partnership with the Tamil Nadu Skill Development Corporation, concluded a transformative 7-day (45-hour) vocational training program across 121 Government Higher Secondary Schools (GHSS). This initiative was designed to empower 12th-grade students with tangible, in-demand skills, paving the way for entrepreneurship and enhancing employability in key growth sectors.", "images": [{"id": "395ee3e7-c26a-41c5-ba76-3ecef4ca5f09", "url": "https://media.rareminds.in/1779541468517-405db03f-bea2-4654-85f5-2d1c62230351-3.jpg"}, {"id": "d1b8fbdb-eee9-46d3-8b41-1b1ee1e39188", "url": "https://media.rareminds.in/1779541475386-72edd8e9-4f8e-4045-a0ee-a3deb4e466ca-2-copy.jpg"}, {"id": "ade6adc8-24ee-4429-a9cd-a13da8e7f489", "url": "https://media.rareminds.in/1779541483045-484282ed-7d08-47f9-b69d-1d82f8536c85-1-copy.jpg"}]}', 2, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:40.335241+00'),
	('29d987ee-8185-4c32-804e-6d0e15ed2a8a', '19a47376-0eb9-5496-82d2-9fa063ec02ca', 'about', 'cards', 'About the Program', 'The program successfully reached 1,974 students allocated by the Tamil Nadu Skill Development Corporation, demonstrating Rareminds'' expertise in large-scale, impactful educational delivery. The 7-day engagement offered students two distinct, yet equally valuable, vocational pathways:', '{"items": [{"id": "9d5b74c2-57b6-46fb-ab40-0d0c046d8f57", "title": "Cloud Kitchen Operations: Encouraging the Entrepreneur", "description": "This stream was designed to give students a comprehensive understanding of the burgeoning cloud kitchen industry, equipping them with the knowledge to launch and manage their food ventures. Five Villupuram schools successfully implemented this program, training 76 aspiring food entrepreneurs."}, {"id": "3fdd009e-dd72-4181-9751-6d6df3717e69", "title": "Agri-Food Processing & Preservation: Cultivating Skills and Opportunities", "description": "This comprehensive 40-hour curriculum equips students with vital knowledge of the agri-food industry, focusing on practical ways to enhance food value, improve safety standards, and extend shelf life. Implemented in 116 schools, 1,570 students gained practical skills. Activities included canning, bottling, pickling, fermentation, drying, and freezing techniques. Students were introduced to food safety principles, hygiene practices, HACCP basics, and quality control measures."}]}', 3, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:40.335241+00'),
	('00eeec38-4c04-45c8-b965-2a9e522e7d4d', '19a47376-0eb9-5496-82d2-9fa063ec02ca', 'strategic_alignment', 'cards', 'Strategic Alignment with TNSDC Goals', NULL, '{"items": [{"id": "c2a5725d-59b7-4cf3-ba3b-ce61e0b66c51", "title": "Entrepreneurship", "description": "Effortless Entrepreneurship alignment through skill-based, experiential learning"}, {"id": "4ed18f9e-cbe0-4894-ad47-8bf13acbcd78", "title": "Employability", "description": "Enhanced student employability with practical, in-demand skills"}, {"id": "83dd1d51-42b9-404e-9aa0-aeaf4fbe076b", "title": "Future-proof Curriculum", "description": "Curriculum in high-growth sectors like food technology and entrepreneurship"}, {"id": "88757402-ca74-498d-ad4f-0a422bcb2309", "title": "Government Partnership", "description": "Proven partnership ensuring reliable implementation of large-scale programs"}, {"id": "60939126-c0ee-482a-8e91-b22d4429fac7", "title": "Integrated Delivery", "description": "Fully integrated program delivery reducing administrative burden for institutions"}, {"id": "3dec2e86-c385-41ae-b439-6fb19b3e4943", "title": "Measurable Impact", "description": "Structured reporting and feedback on student skills and confidence"}], "description": "This initiative supported key institutional objectives such as:"}', 4, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:40.335241+00'),
	('2232cce3-cc59-4770-955d-59706186ba22', '19a47376-0eb9-5496-82d2-9fa063ec02ca', 'conclusion', 'text', 'Conclusion', NULL, '{"text": "This successful GHSS project underscores Rareminds'' dedication to delivering high-quality, large-scale vocational training in collaboration with government bodies. By empowering nearly 2,000 students with practical knowledge and entrepreneurial insights, we are actively shaping a more skilled, confident, and future-ready generation.", "image": {"id": "ac1c65af-bdc0-460c-9814-1d48ea9a47d1", "alt": "", "url": "https://media.rareminds.in/1779540246471-432a943d-0084-4625-b2fe-7d67f004e757-Conclusion-copy.png"}}', 5, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:02:40.335241+00'),
	('81dd8d50-b31b-4162-ac1a-32931dabc56e', '5f257874-6d18-535f-ac5f-54f790db0f03', 'about', 'cards', 'Rareminds Intervention', NULL, '{"items": [{"id": "d2368a45-e9b3-49b8-b05b-7acbf197a131", "title": "Program Overview", "description": "In November 2023, Rareminds conducted a 2-day intensive capacity-building program for 40 teachers at Global International School."}, {"id": "6648af02-f675-4eb5-b1e7-ab9b4ddff29a", "title": "Expert-Led Training", "description": "Led by 3 expert master trainers, the sessions blended foundational understanding with practical application, ensuring teachers gained both theoretical knowledge and hands-on skills."}]}', 6, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00'),
	('978514c4-d2e1-4426-858d-8b9b1659f3ff', '5f257874-6d18-535f-ac5f-54f790db0f03', 'approaches', 'cards', 'Multiple Approaches', NULL, '{"items": [{"id": "9523daff-a220-4abe-95ca-5eb9cea87b51", "title": "Group Activities & Demos", "description": "Interactive Group Activities and Demos"}, {"id": "b03fe304-cad1-403e-8cd6-a667590c1166", "title": "Peer Discussions", "description": "Peer Discussions and Application Circles"}, {"id": "52951313-e55d-4e2a-bb71-6d1b77d1923d", "title": "Micro-Innovation Planning", "description": "Micro-Innovation Planning for Classroom Practice"}]}', 7, '2026-05-11 04:38:12.93941+00', '2026-05-29 11:03:03.526316+00');
